#include "controller.h"

static void controller_set_safe_idle(controller_t *controller)
{
    controller->inlet_open = false;
    controller->heater_on = false;
    controller->state = CONTROLLER_STATE_SAFE_IDLE;
}

void controller_init(controller_t *controller)
{
    if (controller == 0) {
        return;
    }

    controller_set_safe_idle(controller);
    controller->has_valid_temperature = false;
    controller->previous_temperature_c = 0;
    controller->last_temperature_c = 0;
    controller->last_temperature_ms = 0U;
    controller->has_valid_level = false;
    controller->last_level = 0;
    controller->last_level_ms = 0U;
}

controller_output_t controller_step(controller_t *controller, controller_input_t input)
{
    controller_output_t output = {
        .inlet_open = false,
        .heater_on = false,
        .state = CONTROLLER_STATE_SAFE_IDLE,
        .state_name = controller_state_name(CONTROLLER_STATE_SAFE_IDLE),
        .changed = false,
        .timed_out = false,
    };
    bool previous_inlet_open;
    bool previous_heater_on;
    controller_state_t previous_state;

    if (controller == 0) {
        return output;
    }

    previous_inlet_open = controller->inlet_open;
    previous_heater_on = controller->heater_on;
    previous_state = controller->state;

    /* TODO: implement the fill-and-heat policy here. */
    switch (input.kind) {
    case CONTROLLER_INPUT_TEMPERATURE:
        controller->has_valid_temperature = true;
        controller->previous_temperature_c = controller->last_temperature_c;
        controller->last_temperature_c = input.temperature_c;
        controller->last_temperature_ms = input.now_ms;
        controller_set_safe_idle(controller);
        break;
    case CONTROLLER_INPUT_LEVEL:
        controller->has_valid_level = true;
        controller->last_level = input.level;
        controller->last_level_ms = input.now_ms;
        controller_set_safe_idle(controller);
        break;
    case CONTROLLER_INPUT_SENSOR_TIMEOUT:
    case CONTROLLER_INPUT_INVALID_TEMPERATURE:
    case CONTROLLER_INPUT_INVALID_LEVEL:
        controller->has_valid_temperature = false;
        controller->has_valid_level = false;
        controller_set_safe_idle(controller);
        break;
    case CONTROLLER_INPUT_NONE:
    default:
        controller_set_safe_idle(controller);
        break;
    }

    output.inlet_open = controller->inlet_open;
    output.heater_on = controller->heater_on;
    output.state = controller->state;
    output.state_name = controller_state_name(controller->state);
    output.changed =
        (previous_inlet_open != controller->inlet_open) ||
        (previous_heater_on != controller->heater_on) ||
        (previous_state != controller->state);
    return output;
}

const char *controller_state_name(controller_state_t state)
{
    switch (state) {
    case CONTROLLER_STATE_FILLING:
        return "STATE FILLING";
    case CONTROLLER_STATE_HEATING:
        return "STATE HEATING";
    case CONTROLLER_STATE_HOLDING:
        return "STATE HOLDING";
    case CONTROLLER_STATE_SAFE_IDLE:
    default:
        return "STATE SAFE_IDLE";
    }
}

#ifndef CONTROLLER_H
#define CONTROLLER_H

#include <stdbool.h>
#include <stdint.h>

#define CONTROLLER_FILL_LEVEL_THRESHOLD 60
#define CONTROLLER_MIN_HEATING_LEVEL 55
#define CONTROLLER_LEVEL_HIGH_THRESHOLD 75
#define CONTROLLER_TEMP_LOW_THRESHOLD 45
#define CONTROLLER_TEMP_EARLY_OFF_THRESHOLD 47
#define CONTROLLER_TEMP_HIGH_THRESHOLD 48
#define CONTROLLER_SENSOR_TIMEOUT_MS 1000U

typedef enum {
    CONTROLLER_INPUT_NONE = 0,
    CONTROLLER_INPUT_TEMPERATURE,
    CONTROLLER_INPUT_LEVEL,
    CONTROLLER_INPUT_SENSOR_TIMEOUT,
    CONTROLLER_INPUT_INVALID_TEMPERATURE,
    CONTROLLER_INPUT_INVALID_LEVEL,
} controller_input_kind_t;

typedef enum {
    CONTROLLER_STATE_SAFE_IDLE = 0,
    CONTROLLER_STATE_FILLING,
    CONTROLLER_STATE_HEATING,
    CONTROLLER_STATE_HOLDING,
} controller_state_t;

typedef struct {
    controller_input_kind_t kind;
    int temperature_c;
    int level;
    uint32_t now_ms;
} controller_input_t;

typedef struct {
    bool inlet_open;
    bool heater_on;
    controller_state_t state;
    bool has_valid_temperature;
    int previous_temperature_c;
    int last_temperature_c;
    uint32_t last_temperature_ms;
    bool has_valid_level;
    int last_level;
    uint32_t last_level_ms;
} controller_t;

typedef struct {
    bool inlet_open;
    bool heater_on;
    controller_state_t state;
    const char *state_name;
    bool changed;
    bool timed_out;
} controller_output_t;

void controller_init(controller_t *controller);
controller_output_t controller_step(controller_t *controller, controller_input_t input);
const char *controller_state_name(controller_state_t state);

#endif

#include "protocol.h"

#include <ctype.h>
#include <stdio.h>
#include <stdlib.h>
#include <string.h>

static void protocol_reset_input(protocol_input_t *input)
{
    if (input == NULL) {
        return;
    }

    input->kind = PROTOCOL_INPUT_NONE;
    input->temperature_c = 0;
    input->level = 0;
}

static void protocol_trim_copy(const char *line, char *buffer, size_t buffer_size)
{
    size_t source_length;
    size_t start = 0U;
    size_t end;
    size_t length;

    if (buffer_size == 0U) {
        return;
    }

    buffer[0] = '\0';
    if (line == NULL) {
        return;
    }

    source_length = strnlen(line, buffer_size - 1U);
    while ((start < source_length) && isspace((unsigned char) line[start])) {
        start++;
    }

    end = source_length;
    while ((end > start) && isspace((unsigned char) line[end - 1U])) {
        end--;
    }

    length = end - start;
    memcpy(buffer, line + start, length);
    buffer[length] = '\0';
}

static bool protocol_parse_temp_value(const char *token, int *temperature_c)
{
    char *end = NULL;
    long parsed;

    if ((token == NULL) || (temperature_c == NULL)) {
        return false;
    }

    parsed = strtol(token, &end, 10);
    if ((end == token) || (*end != '\0')) {
        return false;
    }

    if ((parsed < 20L) || (parsed > 80L)) {
        return false;
    }

    *temperature_c = (int) parsed;
    return true;
}

static bool protocol_parse_level_value(const char *token, int *level)
{
    char *end = NULL;
    long parsed;

    if ((token == NULL) || (level == NULL)) {
        return false;
    }

    parsed = strtol(token, &end, 10);
    if ((end == token) || (*end != '\0')) {
        return false;
    }

    if ((parsed < 0L) || (parsed > 100L)) {
        return false;
    }

    *level = (int) parsed;
    return true;
}

protocol_parse_result_t protocol_parse_line(const char *line, protocol_input_t *input)
{
    char scratch[PROTOCOL_MAX_LINE_LENGTH];
    char *save = NULL;
    char *first;
    char *second;
    char *third;
    char *fourth;
    int value;

    protocol_reset_input(input);
    protocol_trim_copy(line, scratch, sizeof(scratch));
    if (scratch[0] == '\0') {
        return PROTOCOL_PARSE_IGNORED;
    }

    first = strtok_r(scratch, " \t", &save);
    second = strtok_r(NULL, " \t", &save);
    third = strtok_r(NULL, " \t", &save);
    fourth = strtok_r(NULL, " \t", &save);

    if ((first != NULL) && (second != NULL) && (strcmp(first, "SENSE") == 0) && (strcmp(second, "TEMP") == 0)) {
        if ((third == NULL) || (fourth != NULL) || !protocol_parse_temp_value(third, &value)) {
            if (input != NULL) {
                input->kind = PROTOCOL_INPUT_INVALID_TEMPERATURE;
            }
            return PROTOCOL_PARSE_INVALID_TEMPERATURE;
        }

        if (input != NULL) {
            input->kind = PROTOCOL_INPUT_TEMPERATURE;
            input->temperature_c = value;
        }
        return PROTOCOL_PARSE_TEMPERATURE;
    }

    if ((first != NULL) && (second != NULL) && (strcmp(first, "SENSE") == 0) && (strcmp(second, "LEVEL") == 0)) {
        if ((third == NULL) || (fourth != NULL) || !protocol_parse_level_value(third, &value)) {
            if (input != NULL) {
                input->kind = PROTOCOL_INPUT_INVALID_LEVEL;
            }
            return PROTOCOL_PARSE_INVALID_LEVEL;
        }

        if (input != NULL) {
            input->kind = PROTOCOL_INPUT_LEVEL;
            input->level = value;
        }
        return PROTOCOL_PARSE_LEVEL;
    }

    if ((first != NULL) && (second != NULL) && (strcmp(first, "FAULT") == 0) && (strcmp(second, "SENSOR_TIMEOUT") == 0) && (third == NULL)) {
        if (input != NULL) {
            input->kind = PROTOCOL_INPUT_SENSOR_TIMEOUT;
        }
        return PROTOCOL_PARSE_SENSOR_TIMEOUT;
    }

    return PROTOCOL_PARSE_IGNORED;
}

bool protocol_serialize_act_inlet(bool inlet_open, char *buffer, size_t buffer_size)
{
    const int written = snprintf(buffer, buffer_size, "ACT INLET %s\n", inlet_open ? "OPEN" : "CLOSED");
    return (written >= 0) && ((size_t) written < buffer_size);
}

bool protocol_serialize_act_heater(bool heater_on, char *buffer, size_t buffer_size)
{
    const int written = snprintf(buffer, buffer_size, "ACT HEATER %s\n", heater_on ? "ON" : "OFF");
    return (written >= 0) && ((size_t) written < buffer_size);
}

bool protocol_serialize_debug(const char *message, char *buffer, size_t buffer_size)
{
    const int written = snprintf(buffer, buffer_size, "DBG %s\n", message != NULL ? message : "");
    return (written >= 0) && ((size_t) written < buffer_size);
}

#include "uart_transport.h"

#include <stdbool.h>
#include <stdint.h>
#include <stdio.h>
#include <string.h>

#include "controller.h"
#include "driver/uart.h"
#include "freertos/FreeRTOS.h"
#include "freertos/task.h"
#include "protocol.h"

#define UART_TRANSPORT_PORT UART_NUM_0
#define UART_TRANSPORT_BAUDRATE 115200
#define UART_TRANSPORT_BUFFER_SIZE 256
#define UART_TRANSPORT_LINE_BUFFER_SIZE 128
#define UART_TRANSPORT_HEARTBEAT_MS 1000U
#define UART_TRANSPORT_POLL_MS 50U

typedef struct {
    controller_t controller;
    char rx_line[UART_TRANSPORT_LINE_BUFFER_SIZE];
    size_t rx_line_length;
} uart_transport_context_t;

static uart_transport_context_t s_transport_context;

static uint32_t transport_now_ms(void)
{
    return (uint32_t) (xTaskGetTickCount() * portTICK_PERIOD_MS);
}

static void transport_send_line(const char *line)
{
    if (line == NULL) {
        return;
    }

    uart_write_bytes(UART_TRANSPORT_PORT, line, strlen(line));
}

static void transport_send_debug(const char *message)
{
    char buffer[PROTOCOL_MAX_LINE_LENGTH];
    if (protocol_serialize_debug(message, buffer, sizeof(buffer))) {
        transport_send_line(buffer);
    }
}

static void transport_send_actuators(bool inlet_open, bool heater_on)
{
    char buffer[PROTOCOL_MAX_LINE_LENGTH];
    if (protocol_serialize_act_inlet(inlet_open, buffer, sizeof(buffer))) {
        transport_send_line(buffer);
    }
    if (protocol_serialize_act_heater(heater_on, buffer, sizeof(buffer))) {
        transport_send_line(buffer);
    }
}

static void transport_apply_protocol_input(const protocol_input_t *protocol_input)
{
    controller_input_t controller_input = {
        .kind = CONTROLLER_INPUT_NONE,
        .temperature_c = 0,
        .level = 0,
        .now_ms = transport_now_ms(),
    };

    if (protocol_input == NULL) {
        return;
    }

    switch (protocol_input->kind) {
    case PROTOCOL_INPUT_TEMPERATURE:
        controller_input.kind = CONTROLLER_INPUT_TEMPERATURE;
        controller_input.temperature_c = protocol_input->temperature_c;
        break;
    case PROTOCOL_INPUT_LEVEL:
        controller_input.kind = CONTROLLER_INPUT_LEVEL;
        controller_input.level = protocol_input->level;
        break;
    case PROTOCOL_INPUT_SENSOR_TIMEOUT:
        controller_input.kind = CONTROLLER_INPUT_SENSOR_TIMEOUT;
        break;
    case PROTOCOL_INPUT_INVALID_TEMPERATURE:
        controller_input.kind = CONTROLLER_INPUT_INVALID_TEMPERATURE;
        break;
    case PROTOCOL_INPUT_INVALID_LEVEL:
        controller_input.kind = CONTROLLER_INPUT_INVALID_LEVEL;
        break;
    case PROTOCOL_INPUT_NONE:
    default:
        controller_input.kind = CONTROLLER_INPUT_NONE;
        break;
    }

    controller_output_t output = controller_step(&s_transport_context.controller, controller_input);
    if (output.changed || controller_input.kind != CONTROLLER_INPUT_NONE) {
        transport_send_actuators(output.inlet_open, output.heater_on);
        transport_send_debug(output.state_name);
    }
}

static void transport_handle_received_line(const char *line)
{
    protocol_input_t input = {
        .kind = PROTOCOL_INPUT_NONE,
        .temperature_c = 0,
        .level = 0,
    };

    protocol_parse_result_t result = protocol_parse_line(line, &input);
    if (result == PROTOCOL_PARSE_IGNORED) {
        return;
    }

    transport_apply_protocol_input(&input);
}

static void transport_poll_controller_timeout(void)
{
    controller_input_t controller_input = {
        .kind = CONTROLLER_INPUT_NONE,
        .temperature_c = 0,
        .level = 0,
        .now_ms = transport_now_ms(),
    };

    controller_output_t output = controller_step(&s_transport_context.controller, controller_input);
    if (output.changed) {
        transport_send_actuators(output.inlet_open, output.heater_on);
        transport_send_debug(output.state_name);
    }
}

static void transport_consume_uart_bytes(const uint8_t *bytes, size_t length)
{
    size_t index = 0;

    while (index < length) {
        const char current = (char) bytes[index++];
        if (current == '\r') {
            continue;
        }

        if (current == '\n') {
            s_transport_context.rx_line[s_transport_context.rx_line_length] = '\0';
            if (s_transport_context.rx_line_length > 0U) {
                transport_handle_received_line(s_transport_context.rx_line);
            }
            s_transport_context.rx_line_length = 0U;
            continue;
        }

        if (s_transport_context.rx_line_length + 1U < sizeof(s_transport_context.rx_line)) {
            s_transport_context.rx_line[s_transport_context.rx_line_length++] = current;
        } else {
            s_transport_context.rx_line_length = 0U;
            transport_send_debug("RX_LINE_TOO_LONG");
        }
    }
}

static void transport_task(void *unused)
{
    uint8_t buffer[UART_TRANSPORT_BUFFER_SIZE];
    uint32_t next_heartbeat_ms;

    (void) unused;

    transport_send_debug("BOOTED");
    transport_send_actuators(false, false);
    transport_send_debug("STATE SAFE_IDLE");
    next_heartbeat_ms = transport_now_ms() + UART_TRANSPORT_HEARTBEAT_MS;

    while (true) {
        const int bytes_read = uart_read_bytes(
            UART_TRANSPORT_PORT,
            buffer,
            sizeof(buffer),
            pdMS_TO_TICKS(UART_TRANSPORT_POLL_MS)
        );

        if (bytes_read > 0) {
            transport_consume_uart_bytes(buffer, (size_t) bytes_read);
        }

        transport_poll_controller_timeout();

        if (transport_now_ms() < next_heartbeat_ms) {
            continue;
        }

        transport_send_debug("HEARTBEAT");
        next_heartbeat_ms = transport_now_ms() + UART_TRANSPORT_HEARTBEAT_MS;
    }
}

void uart_transport_start(void)
{
    controller_init(&s_transport_context.controller);
    s_transport_context.rx_line_length = 0U;

    uart_config_t config = {
        .baud_rate = UART_TRANSPORT_BAUDRATE,
        .data_bits = UART_DATA_8_BITS,
        .parity = UART_PARITY_DISABLE,
        .stop_bits = UART_STOP_BITS_1,
        .flow_ctrl = UART_HW_FLOWCTRL_DISABLE,
        .source_clk = UART_SCLK_APB,
    };

    uart_driver_install(UART_TRANSPORT_PORT, UART_TRANSPORT_BUFFER_SIZE * 2, 0, 0, NULL, 0);
    uart_param_config(UART_TRANSPORT_PORT, &config);
    uart_set_pin(UART_TRANSPORT_PORT, UART_PIN_NO_CHANGE, UART_PIN_NO_CHANGE, UART_PIN_NO_CHANGE, UART_PIN_NO_CHANGE);

    xTaskCreate(transport_task, "uart_transport", 4096, NULL, 5, NULL);
}

from __future__ import annotations

import argparse
import json
import os
import re
import shutil
import subprocess
import sys
from datetime import datetime, timezone
from pathlib import Path
from typing import Any


WORKSPACE_ROOT = Path(__file__).resolve().parents[1]
if str(WORKSPACE_ROOT) not in sys.path:
    sys.path.insert(0, str(WORKSPACE_ROOT))


VISIBLE_RUN_ROOT = WORKSPACE_ROOT / "artifacts" / "runs"
EXPERIMENT_PATH = WORKSPACE_ROOT / "experiment.json"
VISIBLE_EDIT_SURFACE_VIOLATION = "VISIBLE_EDIT_SURFACE_VIOLATION"
EVALUATOR_BRIDGE_FAILED = "EVALUATOR_BRIDGE_FAILED"
SUBMISSION_BUDGET_EXHAUSTED = "SUBMISSION_BUDGET_EXHAUSTED"
SUBMISSION_RECORDED = "SUBMISSION_RECORDED"
VISIBLE_PASS = "PASS"
VISIBLE_FAIL = "FAIL"
DEFAULT_LOCAL_PATHS = ["agent_tests"]

BENCHMARK_MODE_DEFAULTS: dict[str, dict[str, Any]] = {
    "oneshot_blind": {
        "submission_feedback": "none",
        "max_submissions": 1,
    },
    "realistic_self_verify": {
        "submission_feedback": "none",
        "max_submissions": None,
    },
    "ci_red_green": {
        "submission_feedback": "red_green",
        "max_submissions": None,
    },
    "oracle_full": {
        "submission_feedback": "oracle_full",
        "max_submissions": None,
    },
}


def _required_env_path(name: str) -> Path:
    value = os.environ.get(name)
    if not value:
        raise RuntimeError(
            f"{name} is not set. This workspace was launched without the hidden evaluator configured. "
            "That is an operator setup issue; the agent should be started with EMBEDDED_EVAL_* already set."
        )
    return Path(value).resolve()


def _load_experiment() -> dict[str, object]:
    return json.loads(EXPERIMENT_PATH.read_text(encoding="utf-8"))


def _normalize_benchmark_config(raw_config: dict[str, Any] | None) -> dict[str, Any]:
    config = dict(raw_config or {})
    mode = str(config.get("mode", "realistic_self_verify")).strip() or "realistic_self_verify"
    if mode not in BENCHMARK_MODE_DEFAULTS:
        available = ", ".join(sorted(BENCHMARK_MODE_DEFAULTS))
        raise RuntimeError(f"unknown benchmark mode: {mode}. available modes: {available}")

    merged = dict(BENCHMARK_MODE_DEFAULTS[mode])
    merged.update(config)
    merged["mode"] = mode

    max_submissions = merged.get("max_submissions")
    if max_submissions in {"", None}:
        merged["max_submissions"] = None
    else:
        merged["max_submissions"] = int(max_submissions)
        if merged["max_submissions"] <= 0:
            raise RuntimeError("benchmark.max_submissions must be positive when provided")

    submission_feedback = str(merged.get("submission_feedback", "")).strip()
    if submission_feedback not in {"none", "red_green", "oracle_full"}:
        raise RuntimeError(
            "benchmark.submission_feedback must be one of: none, red_green, oracle_full"
        )

    return merged


def _local_paths(experiment: dict[str, object]) -> list[str]:
    raw_paths = experiment.get("local_paths", DEFAULT_LOCAL_PATHS)
    return [str(path) for path in raw_paths]


def _manifest_task_spec_path(hidden_root: Path, task_id: str) -> str:
    manifest_path = hidden_root / "experiments" / "tasks" / task_id / "task.json"
    if not manifest_path.exists():
        return ""
    try:
        manifest = json.loads(manifest_path.read_text(encoding="utf-8"))
    except json.JSONDecodeError:
        return ""
    candidate = str(manifest.get("task_spec_path", "")).strip()
    return candidate if candidate else ""


def _resolve_hidden_task_spec_path(hidden_root: Path, experiment: dict[str, object]) -> str:
    candidates = []
    source_task_spec_path = str(experiment.get("source_task_spec_path", "")).strip()
    task_spec_path = str(experiment.get("task_spec_path", "")).strip()
    if source_task_spec_path:
        candidates.append(source_task_spec_path)
    if task_spec_path:
        candidates.append(task_spec_path)
    task_id = str(experiment.get("task_id", "")).strip()
    if task_id:
        manifest_task_spec_path = _manifest_task_spec_path(hidden_root, task_id)
        if manifest_task_spec_path:
            candidates.append(manifest_task_spec_path)
        candidates.append(f"specs/{task_id}.json")

    for candidate in candidates:
        if (hidden_root / candidate).exists():
            return candidate

    return candidates[0] if candidates else ""


def _changed_paths(repo_root: Path) -> list[str]:
    probe = subprocess.run(
        ["git", "rev-parse", "--is-inside-work-tree"],
        cwd=repo_root,
        capture_output=True,
        text=True,
        check=False,
    )
    if probe.returncode != 0 or probe.stdout.strip() != "true":
        return []
    completed = subprocess.run(
        ["git", "status", "--porcelain", "--untracked-files=all"],
        cwd=repo_root,
        capture_output=True,
        text=True,
        check=True,
    )
    return [line[3:] for line in completed.stdout.splitlines() if line]


def _validate_visible_edit_surface(
    repo_root: Path,
    editable_paths: list[str],
    local_paths: list[str],
) -> list[str]:
    allowed_paths = list(editable_paths) + list(local_paths)
    violations = []
    for path in _changed_paths(repo_root):
        if path.startswith("artifacts/"):
            continue
        if any(path == allowed or path.startswith(f"{allowed}/") for allowed in allowed_paths):
            continue
        violations.append(path)
    return violations


def _existing_run_keys(path: Path) -> set[str]:
    if not path.exists():
        return set()
    return {
        str(status_path.parent.relative_to(path))
        for status_path in path.rglob("status.json")
        if status_path.parent.is_dir()
    }


def _pick_hidden_run_dir(path: Path, previous_runs: set[str]) -> Path:
    current_runs = sorted(status_path.parent for status_path in path.rglob("status.json"))
    new_runs = [child for child in current_runs if str(child.relative_to(path)) not in previous_runs]
    if new_runs:
        return new_runs[-1]
    if current_runs:
        return current_runs[-1]
    raise RuntimeError(f"no run directories found under {path}")


def _copy_sync_files_to_hidden(hidden_root: Path, sync_paths: list[str]) -> None:
    for relative in sync_paths:
        source = WORKSPACE_ROOT / relative
        target = hidden_root / relative
        target.parent.mkdir(parents=True, exist_ok=True)
        shutil.copy2(source, target)


def _refresh_latest(visible_run_dir: Path) -> None:
    latest_dir = WORKSPACE_ROOT / "artifacts" / "latest"
    if latest_dir.exists() or latest_dir.is_symlink():
        if latest_dir.is_symlink() or latest_dir.is_file():
            latest_dir.unlink()
        else:
            shutil.rmtree(latest_dir)
    shutil.copytree(visible_run_dir, latest_dir)


def _copy_if_exists(source: Path, target: Path) -> None:
    if not source.exists():
        return
    target.parent.mkdir(parents=True, exist_ok=True)
    shutil.copy2(source, target)


def _load_json_if_exists(path: Path) -> dict[str, Any]:
    if not path.exists():
        return {}
    return json.loads(path.read_text(encoding="utf-8"))


def _hidden_status(hidden_run_dir: Path) -> dict[str, Any]:
    return _load_json_if_exists(hidden_run_dir / "status.json")


def _visible_submission_count() -> int:
    if not VISIBLE_RUN_ROOT.exists():
        return 0
    return sum(1 for _ in VISIBLE_RUN_ROOT.rglob("status.json"))


def _write_json(path: Path, payload: dict[str, Any]) -> None:
    path.parent.mkdir(parents=True, exist_ok=True)
    path.write_text(json.dumps(payload, indent=2, sort_keys=True) + "\n", encoding="utf-8")


def _write_feedback_markdown(path: Path, lines: list[str]) -> None:
    path.parent.mkdir(parents=True, exist_ok=True)
    path.write_text("\n".join(lines) + "\n", encoding="utf-8")


def _write_oracle_feedback(hidden_run_dir: Path, visible_run_dir: Path) -> dict[str, Any]:
    hidden_status = _hidden_status(hidden_run_dir)
    visible_status = {
        "status": hidden_status.get("status"),
        "task_solved": hidden_status.get("task_solved", False),
        "failure_category": hidden_status.get("failure_category", ""),
    }
    _write_json(visible_run_dir / "status.json", visible_status)
    _copy_if_exists(hidden_run_dir / "agent_feedback.json", visible_run_dir / "feedback.json")
    _copy_if_exists(hidden_run_dir / "agent_feedback.md", visible_run_dir / "feedback.md")
    _copy_if_exists(hidden_run_dir / "metrics.json", visible_run_dir / "metrics.json")

    if not (visible_run_dir / "feedback.md").exists():
        fallback = hidden_run_dir / "feedback.json"
        if fallback.exists():
            _write_feedback_markdown(
                visible_run_dir / "feedback.md",
                [json.dumps(json.loads(fallback.read_text(encoding="utf-8")), indent=2, sort_keys=True)],
            )
    return visible_status


def _none_feedback_commentary(benchmark_config: dict[str, Any]) -> list[str]:
    lines = ["Submission recorded. Hidden grader results are withheld in this benchmark mode."]
    if benchmark_config["mode"] == "oneshot_blind":
        lines.append("This workspace intentionally omits the public self-verification helpers for this run.")
    else:
        lines.append("Use the visible build and self-test tools for local iteration.")
    return lines


def _write_none_feedback(
    visible_run_dir: Path,
    *,
    benchmark_config: dict[str, Any],
    submission_index: int,
) -> dict[str, Any]:
    commentary_lines = _none_feedback_commentary(benchmark_config)
    visible_status = {
        "status": SUBMISSION_RECORDED,
        "benchmark_mode": benchmark_config["mode"],
        "submission_index": submission_index,
        "submission_budget": benchmark_config.get("max_submissions"),
    }
    _write_json(visible_run_dir / "status.json", visible_status)
    _write_json(
        visible_run_dir / "feedback.json",
        {
            "status": SUBMISSION_RECORDED,
            "benchmark_mode": benchmark_config["mode"],
            "submission_index": submission_index,
            "submission_budget": benchmark_config.get("max_submissions"),
            "commentary": " ".join(commentary_lines),
        },
    )
    _write_feedback_markdown(
        visible_run_dir / "feedback.md",
        [
            f"Status: {SUBMISSION_RECORDED}",
            "",
            f"Benchmark mode: {benchmark_config['mode']}",
            f"Submission index: {submission_index}",
            f"Submission budget: {benchmark_config.get('max_submissions') or 'unlimited'}",
            "",
            "Commentary:",
            *commentary_lines,
        ],
    )
    return visible_status


def _write_red_green_feedback(
    hidden_run_dir: Path,
    visible_run_dir: Path,
    *,
    benchmark_config: dict[str, Any],
    submission_index: int,
) -> dict[str, Any]:
    hidden_status = _hidden_status(hidden_run_dir)
    task_solved = bool(hidden_status.get("task_solved", False))
    visible_status = {
        "status": VISIBLE_PASS if task_solved else VISIBLE_FAIL,
        "task_solved": task_solved,
        "benchmark_mode": benchmark_config["mode"],
        "submission_index": submission_index,
        "submission_budget": benchmark_config.get("max_submissions"),
    }
    _write_json(visible_run_dir / "status.json", visible_status)
    _write_json(
        visible_run_dir / "feedback.json",
        {
            "status": visible_status["status"],
            "task_solved": task_solved,
            "benchmark_mode": benchmark_config["mode"],
            "submission_index": submission_index,
            "submission_budget": benchmark_config.get("max_submissions"),
            "commentary": "Hidden grader result exposed as red/green only.",
        },
    )
    _write_feedback_markdown(
        visible_run_dir / "feedback.md",
        [
            f"Status: {visible_status['status']}",
            "",
            f"Benchmark mode: {benchmark_config['mode']}",
            f"Submission index: {submission_index}",
            f"Submission budget: {benchmark_config.get('max_submissions') or 'unlimited'}",
            "",
            "Commentary:",
            "Hidden grader result exposed as red/green only.",
        ],
    )
    return visible_status


def _write_feedback(
    hidden_run_dir: Path,
    visible_run_dir: Path,
    *,
    benchmark_config: dict[str, Any],
    submission_index: int,
) -> dict[str, Any]:
    submission_feedback = benchmark_config["submission_feedback"]
    if submission_feedback == "oracle_full":
        visible_status = _write_oracle_feedback(hidden_run_dir, visible_run_dir)
    elif submission_feedback == "red_green":
        visible_status = _write_red_green_feedback(
            hidden_run_dir,
            visible_run_dir,
            benchmark_config=benchmark_config,
            submission_index=submission_index,
        )
    else:
        visible_status = _write_none_feedback(
            visible_run_dir,
            benchmark_config=benchmark_config,
            submission_index=submission_index,
        )

    _refresh_latest(visible_run_dir)
    return visible_status


def _write_local_violation_feedback(visible_run_dir: Path, violations: list[str]) -> dict[str, Any]:
    visible_status = {
        "status": VISIBLE_EDIT_SURFACE_VIOLATION,
        "violations": violations,
    }
    _write_json(visible_run_dir / "status.json", visible_status)
    _write_json(visible_run_dir / "feedback.json", {"status": VISIBLE_EDIT_SURFACE_VIOLATION, "violations": violations})
    feedback_lines = [
        f"Status: {VISIBLE_EDIT_SURFACE_VIOLATION}",
        "",
        "Guidance:",
        "- You changed files outside the allowed task surface.",
        "- Revert edits outside the editable controller files or local test paths and try again.",
        "",
        "Visible edit-surface violations:",
    ]
    feedback_lines.extend(f"- {violation}" for violation in violations)
    _write_feedback_markdown(visible_run_dir / "feedback.md", feedback_lines)

    _refresh_latest(visible_run_dir)
    return visible_status


def _write_submission_budget_feedback(
    visible_run_dir: Path,
    *,
    benchmark_config: dict[str, Any],
    submission_index: int,
) -> dict[str, Any]:
    visible_status = {
        "status": SUBMISSION_BUDGET_EXHAUSTED,
        "benchmark_mode": benchmark_config["mode"],
        "submission_index": submission_index,
        "submission_budget": benchmark_config.get("max_submissions"),
    }
    _write_json(visible_run_dir / "status.json", visible_status)
    _write_json(
        visible_run_dir / "feedback.json",
        {
            "status": SUBMISSION_BUDGET_EXHAUSTED,
            "benchmark_mode": benchmark_config["mode"],
            "submission_index": submission_index,
            "submission_budget": benchmark_config.get("max_submissions"),
            "commentary": "The submission budget for this workspace has been exhausted.",
        },
    )
    _write_feedback_markdown(
        visible_run_dir / "feedback.md",
        [
            f"Status: {SUBMISSION_BUDGET_EXHAUSTED}",
            "",
            f"Benchmark mode: {benchmark_config['mode']}",
            f"Submission index: {submission_index}",
            f"Submission budget: {benchmark_config.get('max_submissions') or 'unlimited'}",
            "",
            "Commentary:",
            "The submission budget for this workspace has been exhausted.",
        ],
    )
    _refresh_latest(visible_run_dir)
    return visible_status


def _write_bridge_failure_feedback(visible_run_dir: Path) -> dict[str, Any]:
    visible_status = {
        "status": EVALUATOR_BRIDGE_FAILED,
        "task_solved": False,
        "failure_category": "evaluator_bridge",
    }
    _write_json(visible_run_dir / "status.json", visible_status)
    _write_json(
        visible_run_dir / "feedback.json",
        {
            "status": EVALUATOR_BRIDGE_FAILED,
            "commentary": (
                "The hidden evaluator did not produce visible feedback. "
                "This is a tooling or operator problem rather than a task-logic result."
            ),
        },
    )
    _write_feedback_markdown(
        visible_run_dir / "feedback.md",
        [
            f"Status: {EVALUATOR_BRIDGE_FAILED}",
            "",
            "Commentary:",
            "The hidden evaluator did not produce visible feedback.",
            "This is a tooling or operator problem rather than a task-logic result.",
        ],
    )
    _refresh_latest(visible_run_dir)
    return visible_status


def _safe_slug(value: str) -> str:
    slug = re.sub(r"[^A-Za-z0-9._-]+", "-", value.strip())
    slug = slug.strip(".-")
    return slug or "unspecified"


def _evaluation_context_from_env() -> dict[str, object]:
    number_fields = {
        "prompt_tokens": "EMBEDDED_EVAL_PROMPT_TOKENS",
        "completion_tokens": "EMBEDDED_EVAL_COMPLETION_TOKENS",
        "total_tokens": "EMBEDDED_EVAL_TOTAL_TOKENS",
        "cost_usd": "EMBEDDED_EVAL_COST_USD",
    }
    string_fields = {
        "framework": "EMBEDDED_EVAL_FRAMEWORK",
        "provider": "EMBEDDED_EVAL_PROVIDER",
        "model": "EMBEDDED_EVAL_MODEL",
        "run_id": "EMBEDDED_EVAL_FRAMEWORK_RUN_ID",
        "benchmark_mode_override": "EMBEDDED_EVAL_BENCHMARK_MODE",
    }

    payload: dict[str, object] = {}
    for key, env_name in string_fields.items():
        value = os.environ.get(env_name, "").strip()
        if value:
            payload[key] = value
    for key, env_name in number_fields.items():
        value = os.environ.get(env_name, "").strip()
        if not value:
            continue
        try:
            payload[key] = int(value)
        except ValueError:
            try:
                payload[key] = float(value)
            except ValueError:
                payload[key] = value
    return payload


def _record_result(
    results_root: Path,
    experiment: dict[str, object],
    resolved_task_spec_path: str,
    benchmark_config: dict[str, Any],
    agent_name: str,
    run_label: str,
    notes: str,
    hidden_run_dir: Path | None,
    visible_run_dir: Path,
    visible_status: dict[str, object],
    submission_index: int,
) -> Path:
    timestamp = visible_run_dir.name
    task_id = str(experiment["task_id"])
    result_dir = results_root / task_id / _safe_slug(agent_name) / timestamp
    result_dir.mkdir(parents=True, exist_ok=True)

    visible_copy_dir = result_dir / "visible_run"
    if visible_copy_dir.exists():
        shutil.rmtree(visible_copy_dir)
    shutil.copytree(visible_run_dir, visible_copy_dir)

    hidden_status = {}
    if hidden_run_dir is not None:
        _copy_if_exists(hidden_run_dir / "summary.md", result_dir / "hidden_summary.md")
        _copy_if_exists(hidden_run_dir / "status.json", result_dir / "hidden_status.json")
        _copy_if_exists(hidden_run_dir / "feedback.json", result_dir / "hidden_feedback.json")
        _copy_if_exists(hidden_run_dir / "agent_feedback.json", result_dir / "hidden_agent_feedback.json")
        _copy_if_exists(hidden_run_dir / "metrics.json", result_dir / "hidden_metrics.json")
        hidden_status = _hidden_status(hidden_run_dir)

    evaluation_context = _evaluation_context_from_env()
    record = {
        "timestamp": timestamp,
        "task_id": task_id,
        "task_name": experiment["task_name"],
        "task_version": experiment["task_version"],
        "task_spec_path": resolved_task_spec_path,
        "feedback": experiment.get("feedback", {}),
        "benchmark": benchmark_config,
        "agent_name": agent_name,
        "run_label": run_label,
        "notes": notes,
        "visible_status": visible_status,
        "status": visible_status["status"],
        "hidden_status": hidden_status,
        "editable_paths": experiment["editable_paths"],
        "sync_paths": experiment.get("sync_paths", experiment["editable_paths"]),
        "local_paths": _local_paths(experiment),
        "submission_index": submission_index,
        "submission_budget": benchmark_config.get("max_submissions"),
        "visible_run_dir": str(visible_run_dir),
        "hidden_run_dir": str(hidden_run_dir) if hidden_run_dir is not None else "",
        "evaluation_context": evaluation_context,
    }
    record.update(evaluation_context)
    _write_json(result_dir / "evaluation.json", record)

    return result_dir


def _strict_exit_code(visible_status: dict[str, object]) -> int:
    status = str(visible_status.get("status", ""))
    if visible_status.get("task_solved", False):
        return 0
    return 0 if status == SUBMISSION_RECORDED else 1


def main() -> int:
    parser = argparse.ArgumentParser(description="Submit the current visible workspace to the hidden evaluator.")
    parser.add_argument(
        "--agent-name",
        default=os.environ.get("EMBEDDED_EVAL_AGENT_NAME", "unspecified-agent"),
        help="Human-readable agent name used when recording results.",
    )
    parser.add_argument(
        "--run-label",
        default=os.environ.get("EMBEDDED_EVAL_RUN_LABEL", ""),
        help="Optional operator-supplied label for this run series.",
    )
    parser.add_argument(
        "--notes",
        default=os.environ.get("EMBEDDED_EVAL_NOTES", ""),
        help="Optional free-form notes stored with the run record.",
    )
    parser.add_argument(
        "--strict-exit-code",
        action="store_true",
        help="Return a non-zero exit code when the visible submission status is a failure.",
    )
    args = parser.parse_args()

    experiment = _load_experiment()
    benchmark_config = _normalize_benchmark_config(experiment.get("benchmark", {}))
    editable_paths = [str(path) for path in experiment["editable_paths"]]
    sync_paths = [str(path) for path in experiment.get("sync_paths", editable_paths)]
    local_paths = _local_paths(experiment)

    hidden_root = _required_env_path("EMBEDDED_EVAL_HARNESS_ROOT")
    hidden_run_root = _required_env_path("EMBEDDED_EVAL_RUN_ROOT")
    results_root = Path(
        os.environ.get("EMBEDDED_EVAL_RESULTS_ROOT", str(hidden_root / "experiments" / "results"))
    ).resolve()
    task_spec_path = _resolve_hidden_task_spec_path(hidden_root, experiment)

    visible_timestamp = datetime.now(timezone.utc).strftime("%Y%m%dT%H%M%SZ")
    visible_run_dir = VISIBLE_RUN_ROOT / visible_timestamp
    visible_run_dir.mkdir(parents=True, exist_ok=True)
    hidden_run_root.mkdir(parents=True, exist_ok=True)
    results_root.mkdir(parents=True, exist_ok=True)

    submission_index = _visible_submission_count() + 1
    max_submissions = benchmark_config.get("max_submissions")
    if max_submissions is not None and submission_index > int(max_submissions):
        visible_status = _write_submission_budget_feedback(
            visible_run_dir,
            benchmark_config=benchmark_config,
            submission_index=submission_index,
        )
        _record_result(
            results_root=results_root,
            experiment=experiment,
            resolved_task_spec_path=task_spec_path,
            benchmark_config=benchmark_config,
            agent_name=args.agent_name,
            run_label=args.run_label,
            notes=args.notes,
            hidden_run_dir=None,
            visible_run_dir=visible_run_dir,
            visible_status=visible_status,
            submission_index=submission_index,
        )
        print((visible_run_dir / "feedback.md").read_text(encoding="utf-8"))
        return _strict_exit_code(visible_status) if args.strict_exit_code else 0

    violations = _validate_visible_edit_surface(WORKSPACE_ROOT, editable_paths, local_paths)
    if violations:
        visible_status = _write_local_violation_feedback(visible_run_dir, violations)
        _record_result(
            results_root=results_root,
            experiment=experiment,
            resolved_task_spec_path=task_spec_path,
            benchmark_config=benchmark_config,
            agent_name=args.agent_name,
            run_label=args.run_label,
            notes=args.notes,
            hidden_run_dir=None,
            visible_run_dir=visible_run_dir,
            visible_status=visible_status,
            submission_index=submission_index,
        )
        print((visible_run_dir / "feedback.md").read_text(encoding="utf-8"))
        return _strict_exit_code(visible_status) if args.strict_exit_code else 0

    _copy_sync_files_to_hidden(hidden_root, sync_paths)
    previous_hidden_runs = _existing_run_keys(hidden_run_root)

    command = ["python3", "tools/agent_loop.py", "--artifact-root", str(hidden_run_root)]
    for editable_path in editable_paths:
        command.extend(["--allowed-edit-path", editable_path])

    if task_spec_path:
        command.extend(["--task-spec", task_spec_path])

    feedback_config = experiment.get("feedback", {})
    if feedback_config:
        command.extend(["--feedback-config-json", json.dumps(feedback_config, sort_keys=True)])

    subprocess.run(command, cwd=hidden_root, check=False, capture_output=True, text=True)

    try:
        hidden_run_dir = _pick_hidden_run_dir(hidden_run_root, previous_hidden_runs)
    except RuntimeError:
        visible_status = _write_bridge_failure_feedback(visible_run_dir)
        _record_result(
            results_root=results_root,
            experiment=experiment,
            resolved_task_spec_path=task_spec_path,
            benchmark_config=benchmark_config,
            agent_name=args.agent_name,
            run_label=args.run_label,
            notes=args.notes,
            hidden_run_dir=None,
            visible_run_dir=visible_run_dir,
            visible_status=visible_status,
            submission_index=submission_index,
        )
        print((visible_run_dir / "feedback.md").read_text(encoding="utf-8"))
        return _strict_exit_code(visible_status) if args.strict_exit_code else 0

    visible_status = _write_feedback(
        hidden_run_dir,
        visible_run_dir,
        benchmark_config=benchmark_config,
        submission_index=submission_index,
    )
    _record_result(
        results_root=results_root,
        experiment=experiment,
        resolved_task_spec_path=task_spec_path,
        benchmark_config=benchmark_config,
        agent_name=args.agent_name,
        run_label=args.run_label,
        notes=args.notes,
        hidden_run_dir=hidden_run_dir,
        visible_run_dir=visible_run_dir,
        visible_status=visible_status,
        submission_index=submission_index,
    )

    print((visible_run_dir / "feedback.md").read_text(encoding="utf-8"))
    return _strict_exit_code(visible_status) if args.strict_exit_code else 0


if __name__ == "__main__":
    raise SystemExit(main())

