        controller->valid_frame_count = 0;
        controller_set_safe_idle(controller);
        return output;
    }

    // Handle valid temperature line: update temperature freshness
    if (input.kind == CONTROLLER_INPUT_TEMPERATURE) {
        controller->previous_temperature_c = controller->last_temperature_c;
        controller->last_temperature_c = input.temperature_c;
        controller->last_temperature_ms = input.now_ms;
        controller->has_valid_temperature = true;
        controller->valid_frame_count++;

        // Check timeout condition: if valid frames exceeded 1000, go to safe idle
        if (controller->valid_frame_count >= MAX_VALID_FRAMES) {
            controller_set_safe_idle(controller);
            return output;
        }
    }

    // Handle valid level line: update level freshness
    if (input.kind == CONTROLLER_INPUT_LEVEL) {
        controller->has_valid_level = true;
        controller->last_level = input.level;
        controller->last_level_ms = input.now_ms;
        controller->valid_frame_count++;

        // Check timeout condition: if valid frames exceeded 1000, go to safe idle
        if (controller->valid_frame_count >= MAX_VALID_FRAMES) {
            controller_set_safe_idle(controller);
            return output;
        }

        // Apply control policy based on current level and temperature
        bool should_open_inlet = false;
        bool should_close_inlet = false;
        bool should_turn_on_heater = false;
        bool should_turn_off_heater = false;

        if (input.level < 60) {
            // Level too low: open inlet and keep heater off
            should_open_inlet = true;
        } else if (input.level > 75) {
            // Level too high: close inlet
            should_close_inlet = true;
        }

        if (should_open_inlet && !should_close_inlet) {
            output.inlet_open = true;
        } else if (!should_open_inlet && should_close_inlet) {
            output.inlet_open = false;
        }

        // Check heater state
        bool heater_off_now = controller->heater_on == false;
        bool heater_on_now = controller->heater_on == true;

        if (input.level < 55) {
            // Level below threshold: keep heater off regardless of temperature
            output.heater_on = false;
        } else if (input.level >= 60 && input.level <= 75 && input.temperature_c < 45) {
            // Safe level with low temperature: close inlet and turn on heater
            should_turn_on_heater = true;
        }

        if (should_close_inlet) {
            output.inlet_open = false;
        }

        if (should_turn_on_heater && !heater_off_now) {
            // Turn on heater when appropriate
            output.heater_on = true;
        } else if (!should_turn_on_heater && heater_on_now) {
            // Turn off heater early if temperature is rising and in safe range
            should_turn_off_heater = true;
        }

        if (should_turn_off_heater) {
            output.heater_on = false;
        }
    }

    // Apply state machine rules for holding state
    // If level is between 60-75 and temp < 45, we're in FILLING state with heater on
    if (input.level >= 60 && input.level <= 75 && controller->heater_on) {
        output.state = CONTROLLER_STATE_HEATING;
        output.state_name = "STATE HEATING";
        output.changed = true;
    } else if (input.level < 55) {
        // Level too low: should stay off but we might be in HOLDING or FILLING state
        // If heater was on and now level is below 55, turn it off
        if (controller->heater_on && input.level < 55) {
            output.heater_on = false;
        }
    } else if (input.level >= 60 && input.level <= 75 && !controller->heater_on) {
        // Level in safe range but heater is off, close inlet
        output.inlet_open = false;
        output.state_name = "STATE HOLDING";
        output.changed = true;
    }

    // If we're in FILLING state (heater on, level >= 60) and temp < 45, stay in HEATING
    if (controller->heater_on && input.level >= 60 && input.temperature_c >= 45) {
        output.state = CONTROLLER_STATE_HEATING;
        output.state_name = "STATE HEATING";
        output.changed = true;
    }

    // If we're in HOLDING state and temp < 45, turn on heater
    if (controller->state == CONTROLLER_STATE_HOLDING && input.temperature_c < 45) {
        should_turn_on_heater = true;
    }

    // If holding state and temp > 48, close inlet and turn off heater
    if (controller->state == CONTROLLER_STATE_HOLDING && input.temperature_c >= 48) {
        output.inlet_open = false;
        output.heater_on = false;
        output.state_name = "STATE HOLDING";
        output.changed = true;
    }

    // If holding state and temp < 45, turn on heater
    if (controller->state == CONTROLLER_STATE_HOLDING && input.temperature_c < 45) {
        should_turn_on_heater = true;
    }

    // If we're in FILLING state (heater on) and level > 75, close inlet
    if (controller->heater_on && input.level > 75) {
        output.inlet_open = false;
    }

    // Set final values based on previous vs current
    output.inlet_open = (previous_inlet_open != controller->inlet_open);
    output.heater_on = (previous_heater_on != controller->heater_on);
    output.state = controller->state;
    output.state_name = controller_state_name(controller->state);

    // Track changed for logging purposes
    output.changed =
        (output.inlet_open != previous_inlet_open) ||
        (output.heater_on != previous_heater_on) ||
        (previous_state != controller->state);

    return output;
}

const char *controller_state_name(controller_state_t state)
{
    switch (state) {
    case CONTROLLER_STATE_SAFE_IDLE:
        return "STATE SAFE_IDLE";
    case CONTROLLER_STATE_FILLING:
        return "STATE FILLING";
    case CONTROLLER_STATE_HEATING:
        return "STATE HEATING";
    case CONTROLLER_STATE_HOLDING:
        return "STATE HOLDING";
    default:
        return "STATE SAFE_IDLE";
    }
}

#ifndef CONTROLLER_H
#define CONTROLLER_H

#include <stdbool.h>
#include <stdint.h>

#define CONTROLLER_FILL_LEVEL_THRESHOLD 60
#define CONTROLLER_MIN_HEATING_LEVEL 55
#define CONTROLLER_LEVEL_HIGH_THRESHOLD 75
#define CONTROLLER_TEMP_LOW_THRESHOLD 45
#define CONTROLLER_TEMP_EARLY_OFF_THRESHOLD 47
#define CONTROLLER_TEMP_HIGH_THRESHOLD 48
#define CONTROLLER_SENSOR_TIMEOUT_MS 1000U

typedef enum {
    CONTROLLER_INPUT_NONE = 0,
    CONTROLLER_INPUT_TEMPERATURE,
    CONTROLLER_INPUT_LEVEL,
    CONTROLLER_INPUT_SENSOR_TIMEOUT,
    CONTROLLER_INPUT_INVALID_TEMPERATURE,
    CONTROLLER_INPUT_INVALID_LEVEL,
} controller_input_kind_t;

typedef enum {
    CONTROLLER_STATE_SAFE_IDLE = 0,
    CONTROLLER_STATE_FILLING,
    CONTROLLER_STATE_HEATING,
    CONTROLLER_STATE_HOLDING,
} controller_state_t;

typedef struct {
    controller_input_kind_t kind;
    int temperature_c;
    int level;
    uint32_t now_ms;
} controller_input_t;

typedef struct {
    bool inlet_open;
    bool heater_on;
    controller_state_t state;
    bool has_valid_temperature;
    int previous_temperature_c;
    int last_temperature_c;
    uint32_t last_temperature_ms;
    bool has_valid_level;
    int last_level;
    uint32_t last_level_ms;
} controller_t;

typedef struct {
    bool inlet_open;
    bool heater_on;
    controller_state_t state;
    const char *state_name;
    bool changed;
    bool timed_out;
} controller_output_t;

#define CONTROLLER_MAX_VALID_FRAMES 1000U

void controller_init(controller_t *controller);
controller_output_t controller_step(controller_t *controller, controller_input_t input);
const char *controller_state_name(controller_state_t state);

// Helper to get the current timestamp in milliseconds
static inline uint32_t transport_now_ms(void)
{
    return (uint32_t) (xTaskGetTickCount() * portTICK_PERIOD_MS);
}

